#include "interface.h"

#include <cstdint>
#include <vector>

uint64_t interval_lookup_sum(
    const std::vector<uint32_t>& starts,
    const std::vector<uint32_t>& ends,
    const std::vector<uint32_t>& payloads,
    const std::vector<uint32_t>& probes,
    const std::vector<uint32_t>& weights,
    int iters) {
  (void)ends;

  const std::size_t num_probes = probes.size();
  const std::size_t num_starts = starts.size();

  if (num_probes == 0 || num_starts == 0) return 0;

  const uint32_t* p_starts = starts.data();
  const uint32_t* p_payloads = payloads.data();
  const uint32_t* p_probes = probes.data();
  const uint32_t* p_weights = weights.data();

  uint64_t sum = 0;

  for (int iter = 0; iter < iters; ++iter) {
    uint64_t iter_sum = 0;
    std::size_t idx = 0;
    for (std::size_t i = 0; i < num_probes; ++i) {
      uint32_t probe = p_probes[i];
      while (idx + 1 < num_starts && p_starts[idx + 1] <= probe) {
        ++idx;
      }
      iter_sum += static_cast<uint64_t>(p_payloads[idx]) * p_weights[i];
    }
    sum = iter_sum;
  }

  return sum;
}
